{/* المربع 4: تعديل المنيو - مع كاروسيل */}
<div className="manager-card">
  <div className="card-title"><span>📝</span> Gestion du menu</div>
  
  {/* أزرار الفئات */}
  <div className="category-tabs">
    {menuCategories.map(cat => (
      <button
        key={cat.id}
        className={`category-tab ${selectedCategoryId === cat.id ? 'active' : ''}`}
        onClick={() => {
          setSelectedCategoryId(cat.id);
          setCurrentProductIndex(0);
        }}
        style={{ borderColor: selectedCategoryId === cat.id ? cat.color : undefined }}
      >
        {cat.icon} {cat.name}
      </button>
    ))}
  </div>
  
  {/* كاروسيل عرض المنتجات */}
  <div className="carousel-container">
    {currentProducts.length > 0 ? (
      <div className="carousel-card">
        <ProductCard
          product={currentProduct}
          category={selectedCategory}
          isEditable={true}
          onEdit={(product) => {
            const newName = prompt("Nouveau nom:", product.name);
            const newPrice = prompt("Nouveau prix:", product.price);
            const newDescription = prompt("Nouvelle description:", product.description || "");
            if (newName && newPrice) {
              updateProduct(selectedCategoryId, product.id, {
                name: newName,
                price: parseFloat(newPrice),
                description: newDescription
              });
            }
          }}
          onDelete={(product) => {
            if (window.confirm(`Supprimer ${product.name} ?`)) {
              deleteProduct(selectedCategoryId, product.id);
            }
          }}
        />
      </div>
    ) : (
      <div className="empty-products">
        <div style={{ fontSize: '3rem', marginBottom: '10px' }}>🍽️</div>
        <p>Aucun produit dans cette catégorie</p>
        <p style={{ fontSize: '0.7rem' }}>Cliquez sur "Ajouter un produit" pour commencer</p>
      </div>
    )}
  </div>
  
  {/* أزرار التنقل */}
  {currentProducts.length > 1 && (
    <>
      <div className="carousel-navigation">
        <button className="nav-arrow" onClick={prevProduct}>◀</button>
        <button className="nav-arrow" onClick={nextProduct}>▶</button>
      </div>
      <div className="product-counter">
        {currentProductIndex + 1} / {currentProducts.length}
      </div>
    </>
  )}
  
  {/* زر إضافة منتج */}
  <button className="add-product-btn" onClick={() => setShowAddProductModal(true)}>
    ➕ Ajouter un produit
  </button>
</div>
